from datetime import datetime

# Load case data from the file
cases_file = locals()['var_functions.query_db:2']
with open(cases_file, 'r') as f:
    cases = json.load(f)

# Load account data
accounts = locals()['var_functions.query_db:6']

# Create a detailed debug
print('__RESULT__:')
debug_info = {
    'total_cases': len(cases),
    'date_range': None,
    'sample_dates': [],
    'account_mappings': 0
}

# Check date ranges
all_dates = []
for case in cases:
    try:
        created_str = case['createddate'].replace('.000+0000', '+00:00').replace('Z', '+00:00')
        created = datetime.fromisoformat(created_str)
        all_dates.append(created)
    except:
        continue

if all_dates:
    debug_info['date_range'] = {
        'min': min(all_dates).isoformat(),
        'max': max(all_dates).isoformat()
    }
    debug_info['sample_dates'] = [d.isoformat() for d in sorted(all_dates)[-10:]]  # Last 10 dates

# Check account mapping
account_ids_in_cases = set()
for case in cases:
    account_ids_in_cases.add(case['accountid'])

# Map accounts both ways
account_state_map = {}
for acc in accounts:
    account_id = acc['Id']
    state = acc['ShippingState']
    account_state_map[account_id] = state
    if account_id.startswith('#'):
        account_state_map[account_id[1:]] = state
    else:
        account_state_map['#' + account_id] = state

# Check how many case accounts can be mapped
mapped_accounts = 0
for acc_id in account_ids_in_cases:
    if acc_id in account_state_map:
        mapped_accounts += 1

debug_info['account_mappings'] = {
    'total_unique_accounts': len(account_ids_in_cases),
    'mapped_accounts': mapped_accounts
}

print(json.dumps(debug_info))"}

